function Changelog({ releases }) {
  const { div, span, h3, p, ul, li } = tags;

  const typeVariant = t => t === 'added' ? 'success' : t === 'fixed' ? 'info' : t === 'changed' ? 'warning' : 'error';

  return div({ class: css('_flex _col _gap0') },
    ...releases.map((release, i) =>
      div({ class: css('_flex _gap4 _pb8 _relative') },
        div({ class: css('_flex _col _aic _w6 _flexShrink0') },
          div({ class: css('_w[12px] _h[12px] _rfull _bgprimary _flexShrink0 _ring2 _ringPrimary') }),
          i < releases.length - 1 ? div({ class: css('_w[2px] _flex1 _bcborder _bgborder') }) : null
        ),
        div({ class: css('_flex _col _gap3 _flex1 _pb4') },
          div({ class: css('_flex _aic _gap3') },
            Badge({ variant: 'primary' }, release.version),
            h3({ class: css('_heading5') }, release.title),
            span({ class: css('_textxs _fgmuted _mla') }, release.date)
          ),
          div({ class: css('_flex _col _gap2') },
            ...release.changes.map(change =>
              div({ class: css('_flex _gap2 _aic') },
                Chip({ label: change.type, size: 'xs', variant: typeVariant(change.type) }),
                span({ class: css('_textsm') }, change.text)
              )
            )
          )
        )
      )
    )
  );
}
